'use server';

import { revalidatePath } from 'next/cache';

export interface ProgramCreator {
  id: string;
  firstName: string;
  lastName: string;
  avatar: string | null;
}

export type ProgramStatus = 'draft' | 'published' | 'archived';

export interface ProgramWithStats {
  id: string;
  title: string;
  type: string;
  eventDates: { start?: string; end?: string };
  visibility: 'public' | 'private';
  registrationStatus: 'open' | 'closed';
  status: ProgramStatus;
  registrantCount: number;
  programValue: number;
  createdBy: ProgramCreator | null;
}

export interface CreateProgramInput {
  title: string;
  status: 'draft' | 'published';
}

export interface CreateProgramResult {
  success: boolean;
  program?: { id: string; title: string };
  error?: string;
}

export async function createProgram(input: CreateProgramInput): Promise<CreateProgramResult> {
  revalidatePath('/programs');
  return { success: true, program: { id: crypto.randomUUID(), title: input.title } };
}

