export async function getAthletesByRegistration(registrationId: string): Promise<RegisteredAthlete[]> {
  return mockAthletes.filter(a => a.registrationId === registrationId);
}

export async function getAllAthleteSubmissions(_organizationId: string): Promise<RegisteredAthlete[]> {
  return mockAthletes;
}

export async function getAthleteBySubmissionId(submissionId: string): Promise<RegisteredAthlete | null> {
  return mockAthletes.find(a => a.submissionId === submissionId) ?? null;
}

